package jetbrains.mps.baseLanguage.unitTest.execution.tool;

/*Generated by MPS */

import com.intellij.execution.testframework.sm.runner.states.TestStateInfo;
import org.jetbrains.annotations.NotNull;

public class TestStateInfoAdapter implements TestStateInfo {
  private final TestState myState;

  public TestStateInfoAdapter(@NotNull TestState state) {
    myState = state;
  }

  @Override
  public boolean isInProgress() {
    return myState.isAnimated();
  }

  @Override
  public boolean isDefect() {
    return myState.isErrored();
  }

  @Override
  public boolean wasLaunched() {
    return myState != TestState.NOT_RAN;
  }

  @Override
  public boolean isFinal() {
    return myState.isFinished();
  }

  @Override
  public boolean wasTerminated() {
    return myState == TestState.TERMINATED;
  }

  @Override
  public TestStateInfo.Magnitude getMagnitude() {
    switch (myState) {
      case SKIPPED:
      case ASSUMPTION_FAILED:
        return TestStateInfo.Magnitude.SKIPPED_INDEX;
      case ERROR:
        return TestStateInfo.Magnitude.ERROR_INDEX;
      case IGNORED:
        return TestStateInfo.Magnitude.IGNORED_INDEX;
      case PASSED:
        return TestStateInfo.Magnitude.PASSED_INDEX;
      case FAILED:
        return TestStateInfo.Magnitude.FAILED_INDEX;
      default:
        return TestStateInfo.Magnitude.COMPLETE_INDEX;

    }
  }
}
